const chatInput = $input.first().json.chatInput || '';
const chatOutput = $input.first().json.output || $input.first().json.chatOutput || '';

const orderMatch = chatOutput.match(/\[ORDER_CONFIRMED\]([\s\S]*?)\[\/ORDER_CONFIRMED\]/);

if (!orderMatch) {
  return [{
    json: {
      hasOrder: false,
      chatOutput: chatOutput,
      message: 'No order confirmed in this message'
    }
  }];
}

const orderBlock = orderMatch[1].trim();
const lines = orderBlock.split('\n').map(l => l.trim()).filter(l => l && l.includes(':'));

const orderData = {};
lines.forEach(line => {
  const separatorIndex = line.indexOf(':');
  if (separatorIndex > 0) {
    const key = line.substring(0, separatorIndex).trim().toLowerCase();
    const value = line.substring(separatorIndex + 1).trim();
    orderData[key] = value;
  }
});

const orderId = 'ORD-' + Date.now().toString().slice(-6);
const now = new Date().toISOString();

const customerName = orderData['name'] || orderData['nombre'] || 'Cliente';
const items = orderData['items'] || orderData['productos'] || '';
const totalStr = (orderData['total'] || '0').replace(/[^0-9]/g, '');
const total = parseInt(totalStr) || 0;

return [{
  json: {
    hasOrder: true,
    chatOutput: chatOutput,
    orderId: orderId,
    customerName: customerName,
    items: items,
    total: total,
    timestamp: now,
    status: 'confirmed'
  }
}];

const order = $input.first().json;

const formattedResponse = '✅ ¡ORDEN CONFIRMADA! 🍕

━━━━━━━━━━━━━━━━━━━━━━
🆔 ID de Orden: ' + order.orderId + '
👤 Cliente: ' + order.customerName + '
📦 Productos: ' + order.items + '
💰 Total: $' + order.total.toLocaleString() + ' COP
⏰ Tiempo estimado: 30-45 minutos
━━━━━━━━━━━━━━━━━━━━━━

¡Gracias por tu compra! 😊🎉';

return [{
  json: {
    chatOutput: formattedResponse
  }
}];

const input = $input.first().json;
const output = input.chatOutput || input.message || 'Error: no response';

return [{
  json: {
    chatOutput: output
  }
}];
